const clientsData = $input.first().json;
const clients = clientsData.list || [];
const now = Date.now();
const windowStart = now + 24*60*60*1000;
const windowEnd = now + 48*60*60*1000;
const todayKey = new Date().toISOString().slice(0,10);

// Backup layer for Stripe's own e-mandate pre-debit notice, not a replacement for it — see
// SETUP.md "RBI pre-debit notification". Only fires for clients with a live recurring
// subscription whose renewal falls 24-48h out, and skips anyone already notified today so a
// re-run/backfill of this workflow doesn't double-send.
const due = clients.filter(c => {
  if (!c.notification_email || !c.notification_email.trim()) return false;
  if (!['active','trialing'].includes(c.plan_status)) return false;
  if (!c.plan_renews_at) return false;
  const renewsAt = new Date(c.plan_renews_at).getTime();
  if (isNaN(renewsAt) || renewsAt < windowStart || renewsAt >= windowEnd) return false;
  if (c.last_renewal_notice_sent && String(c.last_renewal_notice_sent).slice(0,10) === todayKey) return false;
  return true;
});
return due.map(c => ({ json: c }));

const c = $json;
const renewsAt = new Date(c.plan_renews_at);
const dateStr = renewsAt.toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' });
const planLabel = c.plan_name || 'your LeadVyne plan';
return [{
  json: {
    to: c.notification_email,
    subject: `Upcoming renewal — ${planLabel} on ${dateStr}`,
    body: `Hi,\n\nThis is a reminder that your ${planLabel} plan is due to renew on ${dateStr}. If you have a payment method on file, it will be charged automatically around that date.\n\nNo action is needed unless you'd like to change or cancel your plan first — you can do that anytime from Billing \u2192 Customer Portal in your dashboard.\n\nThis is a courtesy reminder in addition to any notice sent directly by our payment processor.\n\n\u2014 LeadVyne`,
    clientId: c.Id
  }
}];
